// Recoit les donnees du devis + le PDF (base64) envoyes par le site.
// Prepare le payload pour creer un template Docuseal a partir du PDF,
// avec un champ de signature place sur la zone "Signature du client"
// (coin bas-gauche du PDF genere par generateDevisPdf.ts).
const body = $json.body || $json;
const numero = body.devis_numero || 'sans-numero';
const name = `Devis ${numero}`.trim();

const templateData = {
  name,
  documents: [
    {
      name,
      file: body.pdf_base64,
      fields: [
        {
          name: 'Signature',
          type: 'signature',
          role: 'Client',
          required: true,
          areas: [{ x: 0.08, y: 0.83, w: 0.34, h: 0.06, page: 0 }],
        },
      ],
    },
  ],
};

// Metadonnees du rendez-vous : transportees jusqu'au webhook form.completed
// pour creer l'evenement calendrier apres signature.
const metadata = {
  date: body.date || '',
  heure: body.heure || '',
  prenom: body.prenom || '',
  nom: body.nom || '',
  telephone: body.telephone || '',
  email: body.email || '',
  adresse: body.adresse || '',
  surface_m2: String(body.surface_m2 || ''),
  type_toiture: body.type_toiture || '',
  devis_total_ttc: String(body.devis_total_ttc || ''),
  devis_numero: numero,
};

return [{ json: { templateData, metadata, body } }];

// Lit la reponse de creation du template (contient l'id) et construit
// la soumission : un signataire (le client) qui recevra le lien par email.
const resp = $json;
const templateId = resp.id;
const prep = $('Prepare Template').first().json;
const body = prep.body;
const metadata = prep.metadata;

const submissionData = {
  template_id: templateId,
  send_email: true,
  submitters: [
    {
      role: 'Client',
      name: `${body.prenom || ''} ${body.nom || ''}`.trim(),
      email: body.email,
      metadata: metadata,
    },
  ],
};

return [{ json: { submissionData } }];
